CREATE OR REPLACE FUNCTION app.process_order(p_order_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO audit.audit_log (table_name, action) VALUES ('orders', 'processed');
  INSERT INTO audit.audit_log (table_name, action) VALUES ('order_items', 'processed');
  SELECT id FROM app.products WHERE id = 1;
END;
$function$

CREATE OR REPLACE FUNCTION app.dynamic_query(tbl text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  sql text;
BEGIN
  sql := format('SELECT * FROM %I', tbl);
  EXECUTE sql;
END;
$function$

CREATE OR REPLACE FUNCTION app.audit_fn()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO audit.audit_log (table_name, action) VALUES (TG_TABLE_NAME, TG_OP);
  RETURN NEW;
END;
$function$
